// Global variables for progress tracking
let activeSession = {
  status: 'idle', // idle, scanning, decrypting, completed, failed
  progress: 0,
  totalFiles: 0,
  processedFiles: 0,
  decryptedCount: 0,
  copiedCount: 0,
  failedCount: 0,
  currentFile: '',
  elapsedTime: '0s',
  speed: '0 files/s',
  logs: [],
  inputPath: '',
  outputPath: '',
  key: '',
  gameTitle: 'Unknown Game',
  engineType: 'Unknown'
};

// SSE clients
let sseClients = [];

// Helper to push logs to session and broadcast to SSE clients
function logMessage(level, message) {
  const time = new Date().toLocaleTimeString();
  const logEntry = { time, level, message };
  activeSession.logs.push(logEntry);
  if (activeSession.logs.length > 500) {
    activeSession.logs.shift(); // Keep logs reasonable
  }
  broadcast({ type: 'log', data: logEntry });
}

// Broadcast helper for SSE
function broadcast(eventData) {
  const dataString = `data: ${JSON.stringify(eventData)}\n\n`;
  sseClients.forEach(client => {
    client.write(dataString);
  });
}

// Helper to scan directory recursively
function scanDirRecursive(dir, fileList = []) {
  if (!fs.existsSync(dir)) return fileList;
  const files = fs.readdirSync(dir);
  for (const file of files) {
    const fullPath = path.join(dir, file);
    try {
      const stat = fs.statSync(fullPath);
      if (stat.isDirectory()) {
        scanDirRecursive(fullPath, fileList);
      } else {
        fileList.push(fullPath);
      }
    } catch (e) {
      // Ignore files we can't access
    }
  }
  return fileList;
}

// Extract Encryption Key from System.json
function extractKey(dirPath) {
  // Common paths for System.json
  const possiblePaths = [
    path.join(dirPath, 'data', 'System.json'),        // RPG Maker MZ standard
    path.join(dirPath, 'www', 'data', 'System.json'),  // RPG Maker MV standard
  ];

  for (const sysPath of possiblePaths) {
    if (fs.existsSync(sysPath)) {
      try {
        const content = fs.readFileSync(sysPath, 'utf8');
        const data = JSON.parse(content);
        if (data.encryptionKey) {
          const key = data.encryptionKey;
          const engine = sysPath.includes('www') ? 'RPG Maker MV' : 'RPG Maker MZ';
          const title = data.gameTitle || 'RPG Maker Game';
          return { key, engine, title, systemPath: sysPath };
        }
      } catch (e) {
        logMessage('WARNING', `Failed to parse ${sysPath}: ${e.message}`);
      }
    }
  }
  return null;
}

// Heuristic method: crack key by XORing the first 16 bytes of an encrypted PNG (after signature) with the standard PNG header
function crackKeyFromAssets(allFiles) {
  const pngHeader = [0x89, 0x50, 0x4e, 0x47, 0x0d, 0x0a, 0x1a, 0x0a, 0x00, 0x00, 0x00, 0x0d, 0x49, 0x48, 0x44, 0x52];
  
  // Find first encrypted PNG file (.rpgmvp or .png_)
  const encryptedPng = allFiles.find(file => {
    const ext = path.extname(file).toLowerCase();
    return ext === '.rpgmvp' || ext === '.png_';
  });

  if (encryptedPng && fs.existsSync(encryptedPng)) {
    try {
      const fd = fs.openSync(encryptedPng, 'r');
      const buffer = Buffer.alloc(32);
      fs.readSync(fd, buffer, 0, 32, 0);
      fs.closeSync(fd);

      // Verify signature starts with 'RPGM'
      if (buffer.toString('ascii', 0, 4) === 'RPGM') {
        const keyBytes = Buffer.alloc(16);
        for (let i = 0; i < 16; i++) {
          keyBytes[i] = buffer[16 + i] ^ pngHeader[i];
        }
        const crackedKey = keyBytes.toString('hex');
        logMessage('SUCCESS', `Successfully cracked key from PNG signature of: ${path.basename(encryptedPng)}`);
        return crackedKey;
      }
    } catch (e) {
      logMessage('WARNING', `Failed to crack key from asset ${encryptedPng}: ${e.message}`);
    }
  }
  return null;
}

// Open folder helper
function openFolderInExplorer(folderPath) {
  const platform = process.platform;
  if (platform === 'win32') {
    exec(`explorer "${folderPath}"`);
  } else if (platform === 'darwin') {
    exec(`open "${folderPath}"`);
  } else {
    exec(`xdg-open "${folderPath}"`);
  }
}

// Decrypt buffer using XOR
function decryptBuffer(buffer, keyHex) {
  const headerSize = 16;
  const xorSize = 16;

  // Check if buffer is large enough and starts with RPG signature
  if (buffer.length < headerSize) {
    return { decrypted: false, data: buffer };
  }

  // RPG Maker signatures: RPGMVP, RPGMVM, RPGMVO
  const sig = buffer.toString('ascii', 0, 4);
  if (sig !== 'RPGM') {
    return { decrypted: false, data: buffer };
  }

  const keyBytes = Buffer.from(keyHex, 'hex');
  if (keyBytes.length === 0) {
    throw new Error('Invalid encryption key (empty or non-hex)');
  }

  // Strip header (16 bytes)
  const payload = Buffer.alloc(buffer.length - headerSize);
  buffer.copy(payload, 0, headerSize);

  // XOR first 16 bytes of the payload
  const limit = Math.min(payload.length, xorSize);
  for (let i = 0; i < limit; i++) {
    payload[i] = payload[i] ^ keyBytes[i % keyBytes.length];
  }

  return { decrypted: true, data: payload };
}

// Helper to determine original extension and if file is encrypted
function getTargetFileInfo(filePath) {
  const ext = path.extname(filePath).toLowerCase();
  let newExt = ext;
  let isEncryptedType = false;

  switch (ext) {
    case '.rpgmvp':
      newExt = '.png';
      isEncryptedType = true;
      break;
    case '.rpgmvm':
      newExt = '.m4a';
      isEncryptedType = true;
      break;
    case '.rpgmvo':
      newExt = '.ogg';
      isEncryptedType = true;
      break;
    case '.rpgwma':
      newExt = '.wma';
      isEncryptedType = true;
      break;
    case '.png_':
      newExt = '.png';
      isEncryptedType = true;
      break;
    case '.ogg_':
      newExt = '.ogg';
      isEncryptedType = true;
      break;
    case '.m4a_':
      newExt = '.m4a';
      isEncryptedType = true;
      break;
  }

  return { isEncryptedType, newExt };
}

// Main Decryption Process running asynchronously
async function runDecryption(inputPath, outputPath, keyHex) {
  activeSession.status = 'decrypting';
  activeSession.processedFiles = 0;
  activeSession.decryptedCount = 0;
  activeSession.copiedCount = 0;
  activeSession.failedCount = 0;
  activeSession.progress = 0;
  activeSession.inputPath = inputPath;
  activeSession.outputPath = outputPath;
  activeSession.key = keyHex;

  logMessage('INFO', `Starting decryption to: ${outputPath}`);
  
  const startTime = Date.now();
  let fileList = [];
  try {
    logMessage('INFO', `Scanning source directory...`);
    fileList = scanDirRecursive(inputPath);
    activeSession.totalFiles = fileList.length;
    logMessage('INFO', `Found ${fileList.length} files in total.`);
    broadcast({ type: 'session', data: activeSession });
  } catch (e) {
    activeSession.status = 'failed';
    logMessage('ERROR', `Scan directory failed: ${e.message}`);
    broadcast({ type: 'session', data: activeSession });
    return;
  }

  if (fileList.length === 0) {
    activeSession.status = 'completed';
    activeSession.progress = 100;
    logMessage('SUCCESS', 'No files to process.');
    broadcast({ type: 'session', data: activeSession });
    return;
  }

  // Process batch
  let lastBroadcastTime = 0;
  for (let i = 0; i < fileList.length; i++) {
    const file = fileList[i];
    const relPath = path.relative(inputPath, file);
    activeSession.currentFile = relPath;
    
    // Determine target output path
    const { isEncryptedType, newExt } = getTargetFileInfo(file);
    const targetRelPath = isEncryptedType ? relPath.slice(0, -path.extname(relPath).length) + newExt : relPath;
    const targetPath = path.join(outputPath, targetRelPath);

    // Ensure directory exists
    const targetDir = path.dirname(targetPath);
    if (!fs.existsSync(targetDir)) {
      fs.mkdirSync(targetDir, { recursive: true });
    }

    try {
      if (isEncryptedType) {
        // Read file
        const buffer = fs.readFileSync(file);
        const { decrypted, data } = decryptBuffer(buffer, keyHex);
        
        if (decrypted) {
          fs.writeFileSync(targetPath, data);
          activeSession.decryptedCount++;
          if (activeSession.decryptedCount % 500 === 0) {
            logMessage('INFO', `已还原解密 ${activeSession.decryptedCount} 个文件...`);
          }
        } else {
          // It had the extension but signature didn't match. Copy as-is.
          fs.writeFileSync(targetPath, buffer);
          activeSession.copiedCount++;
          logMessage('WARNING', `Signature mismatch for ${relPath}, copied as-is.`);
        }
      } else {
        // Intercept System.json to disable encryption flags in the decrypted output
        const isSystemJson = path.basename(file).toLowerCase() === 'system.json';
        if (isSystemJson) {
          try {
            const content = fs.readFileSync(file, 'utf8');
            const data = JSON.parse(content);
            let modified = false;
            if (data.hasEncryptedImages === true) {
              data.hasEncryptedImages = false;
              modified = true;
            }
            if (data.hasEncryptedAudio === true) {
              data.hasEncryptedAudio = false;
              modified = true;
            }
            if (modified) {
              fs.writeFileSync(targetPath, JSON.stringify(data, null, 2));
              activeSession.copiedCount++;
              logMessage('SUCCESS', `Modified System.json: Disabled encryption flags so game runs unencrypted.`);
            } else {
              fs.copyFileSync(file, targetPath);
              activeSession.copiedCount++;
            }
          } catch (e) {
            logMessage('WARNING', `Failed to patch System.json, copying as-is: ${e.message}`);
            fs.copyFileSync(file, targetPath);
            activeSession.copiedCount++;
          }
        } else {
          // Regular copy
          fs.copyFileSync(file, targetPath);
          activeSession.copiedCount++;
        }
      }
    } catch (err) {
      activeSession.failedCount++;
      logMessage('ERROR', `Failed to process ${relPath}: ${err.message}`);
    }

    // Update stats
    activeSession.processedFiles = i + 1;
    activeSession.progress = Math.round((activeSession.processedFiles / activeSession.totalFiles) * 100);

    // Calculate speed and elapsed time
    const elapsedMs = Date.now() - startTime;
    const seconds = Math.max(1, Math.round(elapsedMs / 1000));
    activeSession.elapsedTime = `${seconds}s`;
    activeSession.speed = `${Math.round(activeSession.processedFiles / seconds)} files/s`;

    // Throttle UI broadcasts (at most once every 100ms, or on final file)
    const now = Date.now();
    if (now - lastBroadcastTime > 100 || i === fileList.length - 1) {
      broadcast({ type: 'session', data: activeSession });
      lastBroadcastTime = now;
      // Add small sleep to allow Node event loop to process network events
      await new Promise(resolve => setTimeout(resolve, 1));
    }
  }

  activeSession.status = 'completed';
  activeSession.progress = 100;
  activeSession.currentFile = '';
  const totalTime = ((Date.now() - startTime) / 1000).toFixed(1);
  logMessage('SUCCESS', `Decryption completed in ${totalTime}s! Decrypted: ${activeSession.decryptedCount}, Copied: ${activeSession.copiedCount}, Failed: ${activeSession.failedCount}`);
  broadcast({ type: 'session', data: activeSession });
}

