const JS_CONTENT = `// Connect to SSE stream
let eventSource = null;

function setupEventSource() {
  if (eventSource) {
    eventSource.close();
  }
  
  eventSource = new EventSource('/api/progress');
  
  eventSource.onmessage = function(event) {
    const data = JSON.parse(event.data);
    if (data.type === 'session') {
      updateUI(data.data);
    } else if (data.type === 'log') {
      appendLog(data.data);
    }
  };

  eventSource.onerror = function() {
    console.log('SSE connection error. Retrying...');
    setTimeout(setupEventSource, 2000);
  };
}

// Append log helper
const consoleLogs = document.getElementById('console-logs');
function appendLog(log) {
  const div = document.createElement('div');
  div.className = 'log-line ' + log.level.toLowerCase();
  
  const spanTime = document.createElement('span');
  spanTime.className = 'log-time';
  spanTime.textContent = '[' + log.time + ']';
  
  const spanText = document.createTextNode(' [' + log.level + '] ' + log.message);
  
  div.appendChild(spanTime);
  div.appendChild(spanText);
  consoleLogs.appendChild(div);
  
  // Auto scroll
  consoleLogs.scrollTop = consoleLogs.scrollHeight;
}

// Update DOM elements using session stats
function updateUI(session) {
  // Update stats
  document.getElementById('stat-total').textContent = session.totalFiles || 0;
  document.getElementById('stat-decrypted').textContent = session.decryptedCount || 0;
  document.getElementById('stat-copied').textContent = session.copiedCount || 0;
  document.getElementById('stat-failed').textContent = session.failedCount || 0;
  
  // Update progress bar
  document.getElementById('progress-percent').textContent = session.progress + '%';
  document.getElementById('progress-fill').style.width = session.progress + '%';
  
  // Update file info
  if (session.status === 'decrypting') {
    document.getElementById('progress-file-info').textContent = '正在处理: ' + session.currentFile;
  } else if (session.status === 'completed') {
    document.getElementById('progress-file-info').textContent = '处理完成';
  } else if (session.status === 'failed') {
    document.getElementById('progress-file-info').textContent = '解密失败';
  } else if (session.status === 'scanning') {
    document.getElementById('progress-file-info').textContent = '正在扫描目录...';
  } else {
    document.getElementById('progress-file-info').textContent = '准备就绪...';
  }
  
  // Meta
  document.getElementById('speed-val').textContent = '速度: ' + session.speed;
  document.getElementById('time-val').textContent = '耗时: ' + session.elapsedTime;
  
  // Disable buttons while running
  const inputsDisabled = ['decrypting', 'scanning'].includes(session.status);
  document.getElementById('btn-scan').disabled = inputsDisabled;
  document.getElementById('btn-start').disabled = inputsDisabled || !session.key;
  document.getElementById('input-path').disabled = inputsDisabled;
  document.getElementById('key-override').disabled = inputsDisabled;
  document.getElementById('output-name').disabled = inputsDisabled;
  
  // Show/Hide completion actions
  const completeActions = document.getElementById('complete-actions');
  if (session.status === 'completed' && session.totalFiles > 0) {
    completeActions.classList.remove('hide');
  } else {
    completeActions.classList.add('hide');
  }
}

// DOM Events
document.addEventListener('DOMContentLoaded', () => {
  setupEventSource();
  
  const btnScan = document.getElementById('btn-scan');
  const btnStart = document.getElementById('btn-start');
  const btnClearLogs = document.getElementById('btn-clear-logs');
  const btnOpenFolder = document.getElementById('btn-open-folder');
  const gameInfoCard = document.getElementById('game-info');

  // Clear local console
  btnClearLogs.addEventListener('click', () => {
    consoleLogs.innerHTML = '';
  });

  // Scan folder
  btnScan.addEventListener('click', async () => {
    const inputPath = document.getElementById('input-path').value.trim();
    if (!inputPath) {
      alert('请输入游戏目录绝对路径！');
      return;
    }
    
    appendLog({ time: new Date().toLocaleTimeString(), level: 'SYSTEM', message: '发起目录扫描: ' + inputPath });
    
    try {
      const res = await fetch('/api/scan', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ inputPath })
      });
      const data = await res.json();
      
      if (data.success) {
        // Show detected info
        gameInfoCard.classList.remove('hide');
        document.getElementById('info-engine').textContent = data.engineType;
        document.getElementById('info-title').textContent = data.gameTitle;
        document.getElementById('info-key').textContent = data.encryptionKey || '未检测到Key';
        document.getElementById('info-files').textContent = data.encryptedFilesCount;
        
        // Auto fill key override input if detected
        if (data.encryptionKey) {
          document.getElementById('key-override').value = data.encryptionKey;
          btnStart.disabled = false;
        } else {
          appendLog({ time: new Date().toLocaleTimeString(), level: 'WARNING', message: '未能自动检测到解密密钥，请在下方手动输入密钥。' });
          btnStart.disabled = true;
        }
        
        appendLog({ time: new Date().toLocaleTimeString(), level: 'SYSTEM', message: '目录扫描完毕。找到加密文件：' + data.encryptedFilesCount });
      } else {
        alert('扫描失败: ' + data.message);
        gameInfoCard.classList.add('hide');
        btnStart.disabled = true;
      }
    } catch (err) {
      alert('扫描异常: ' + err.message);
      btnStart.disabled = true;
    }
  });

  // Start Decryption
  btnStart.addEventListener('click', async () => {
    const inputPath = document.getElementById('input-path').value.trim();
    const key = document.getElementById('key-override').value.trim();
    const outputName = document.getElementById('output-name').value.trim();
    
    if (!inputPath || !key) {
      alert('游戏路径或解密密钥不能为空！');
      return;
    }
    if (key.length !== 32) {
      alert('密钥长度必须为32位十六进制字符！');
      return;
    }
    
    try {
      const res = await fetch('/api/decrypt', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ inputPath, key, outputName })
      });
      const data = await res.json();
      if (!data.success) {
        alert('启动解密失败: ' + data.message);
      }
    } catch (err) {
      alert('启动解密异常: ' + err.message);
    }
  });

  // Open output folder
  btnOpenFolder.addEventListener('click', async () => {
    try {
      await fetch('/api/open-folder', { method: 'POST' });
    } catch (err) {
      console.error(err);
    }
  });
});
`;

// API routes and HTTP requests
const server = http.createServer((req, res) => {
  const reqUrl = new URL(req.url, `http://${req.headers.host || 'localhost'}`);

  // Static Assets
  if (req.method === 'GET' && (reqUrl.pathname === '/' || reqUrl.pathname === '/index.html')) {
    res.writeHead(200, { 'Content-Type': 'text/html; charset=utf-8' });
    res.end(HTML_CONTENT);
    return;
  }
  
  if (req.method === 'GET' && reqUrl.pathname === '/style.css') {
    res.writeHead(200, { 'Content-Type': 'text/css; charset=utf-8' });
    res.end(CSS_CONTENT);
    return;
  }

  if (req.method === 'GET' && reqUrl.pathname === '/main.js') {
    res.writeHead(200, { 'Content-Type': 'application/javascript; charset=utf-8' });
    res.end(JS_CONTENT);
    return;
  }

  if (req.method === 'GET' && reqUrl.pathname === '/favicon.png') {
    if (FAVICON_BASE64) {
      res.writeHead(200, { 'Content-Type': 'image/png' });
      res.end(Buffer.from(FAVICON_BASE64, 'base64'));
    } else {
      res.writeHead(404);
      res.end();
    }
    return;
  }

  // SSE progress stream
  if (req.method === 'GET' && reqUrl.pathname === '/api/progress') {
    res.writeHead(200, {
      'Content-Type': 'text/event-stream',
      'Cache-Control': 'no-cache',
      'Connection': 'keep-alive'
    });
    res.write('\n'); // keep connection alive initial heartbeat
    sseClients.push(res);
    
    // Broadcast initial state
    res.write(`data: ${JSON.stringify({ type: 'session', data: activeSession })}\n\n`);
    
    req.on('close', () => {
      sseClients = sseClients.filter(c => c !== res);
    });
    return;
  }

  // Scan Directory API
  if (req.method === 'POST' && reqUrl.pathname === '/api/scan') {
    let body = '';
    req.on('data', chunk => { body += chunk; });
    req.on('end', () => {
      try {
        const { inputPath } = JSON.parse(body);
        if (!inputPath || !fs.existsSync(inputPath)) {
          res.writeHead(400, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ success: false, message: '游戏目录不存在，请检查绝对路径！' }));
          return;
        }

        activeSession.status = 'scanning';
        broadcast({ type: 'session', data: activeSession });

        const detection = extractKey(inputPath);
        const allFiles = scanDirRecursive(inputPath);
        
        let encryptedCount = 0;
        allFiles.forEach(file => {
          const ext = path.extname(file).toLowerCase();
          if (['.rpgmvp', '.rpgmvm', '.rpgmvo', '.rpgwma', '.png_', '.ogg_', '.m4a_'].includes(ext)) {
            encryptedCount++;
          }
        });

        activeSession.status = 'idle';
        activeSession.totalFiles = allFiles.length;
        activeSession.logs = []; // Clear old logs on new scan
        
        let detectedKey = detection ? detection.key : '';
        let engineType = detection ? detection.engine : 'Unknown / Custom RPG Engine';
        let gameTitle = detection ? detection.title : path.basename(inputPath);
        
        if (!detectedKey) {
          logMessage('INFO', 'Searching encrypted assets to crack the key...');
          const crackedKey = crackKeyFromAssets(allFiles);
          if (crackedKey) {
            detectedKey = crackedKey;
            engineType += ' (Key Cracked)';
            logMessage('SUCCESS', `Key Cracked: ${crackedKey}`);
          }
        }
        
        activeSession.gameTitle = gameTitle;
        activeSession.engineType = engineType;
        activeSession.key = detectedKey;
        
        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({
          success: true,
          gameTitle: gameTitle,
          engineType: engineType,
          encryptionKey: detectedKey,
          encryptedFilesCount: encryptedCount,
          totalFilesCount: allFiles.length
        }));
        broadcast({ type: 'session', data: activeSession });
      } catch (err) {
        res.writeHead(500, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ success: false, message: err.message }));
      }
    });
    return;
  }

  // Start Decryption API
  if (req.method === 'POST' && reqUrl.pathname === '/api/decrypt') {
    let body = '';
    req.on('data', chunk => { body += chunk; });
    req.on('end', () => {
      try {
        const { inputPath, key, outputName } = JSON.parse(body);
        if (!inputPath || !fs.existsSync(inputPath) || !key) {
          res.writeHead(400, { 'Content-Type': 'application/json' });
          res.end(JSON.stringify({ success: false, message: '输入参数无效！' }));
          return;
        }

        // Establish output path
        const parentDir = path.dirname(inputPath);
        const folderName = outputName || `${path.basename(inputPath)}_decrypted`;
        const outputPath = path.join(parentDir, folderName);

        // Run async decryption
        runDecryption(inputPath, outputPath, key);

        res.writeHead(200, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ success: true, message: '解密任务已启动。' }));
      } catch (err) {
        res.writeHead(500, { 'Content-Type': 'application/json' });
        res.end(JSON.stringify({ success: false, message: err.message }));
      }
    });
    return;
  }

  // Open output folder API
  if (req.method === 'POST' && reqUrl.pathname === '/api/open-folder') {
    if (activeSession.outputPath && fs.existsSync(activeSession.outputPath)) {
      openFolderInExplorer(activeSession.outputPath);
      res.writeHead(200, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ success: true }));
    } else {
      res.writeHead(400, { 'Content-Type': 'application/json' });
      res.end(JSON.stringify({ success: false, message: '目录尚未创建或为空！' }));
    }
    return;
  }

  // 404
  res.writeHead(404, { 'Content-Type': 'text/plain' });
  res.end('404 Not Found');
});

// Auto-find port or default to 3000
let currentPort = 3000;
server.on('error', (err) => {
  if (err.code === 'EADDRINUSE' || err.code === 'EACCES') {
    console.log(`Port ${currentPort} is busy or restricted, trying port ${currentPort + 1}...`);
    currentPort++;
    if (currentPort > 3100) {
      console.error('Could not find any available port.');
      process.exit(1);
    }
    server.listen(currentPort, '127.0.0.1');
  } else {
    console.error('Server error:', err);
  }
});

server.listen(currentPort, '127.0.0.1', () => {
  const url = `http://localhost:${currentPort}`;
  console.log(`Server running at ${url}`);
  
  // Try to auto-open browser
  const cmd = process.platform === 'win32' ? `start ${url}` : process.platform === 'darwin' ? `open ${url}` : `xdg-open ${url}`;
  exec(cmd, (err) => {
    if (err) {
      console.log(`Could not automatically open browser. Please navigate to ${url} manually.`);
    }
  });
});
